import { fallbackEnUs, t } from "@/global";
import styles from '../Login/index.less';
import { useLocation } from "@umijs/max";
import { ProCard } from "@ant-design/pro-card";
import Footer from "@/components/Footer";
import { Button, theme, Input, message } from "antd";
import { useState } from "react";
import { getLoginVerificationCode, linkOidcAccount, login } from "@/services/api";
import { ResponseError } from "umi-request";
import { API } from "@/services/typings";
import axios from 'axios';
import { LangAndTheme } from "@/components/RightContent";

const { useToken } = theme;

function capitalizeWithRegex(str: string): string {
  return str.replace(/^./, (firstChar) => firstChar.toUpperCase()).toLowerCase().replace(/^./, (firstChar) => firstChar.toUpperCase());
}

const Step2Content = ({ inputCode, setInputCode, email }: {
  inputCode: string;
  setInputCode: (value: string) => void;
  email: string;
}) => {
  const { token: themeToken } = theme.useToken();

  return (
    <>
      <div style={{ fontSize: '18px', fontWeight: 500, color: themeToken.colorText }}>
        Enter code
      </div>
      <br />
      <div style={{ color: themeToken.colorText }}>We emailed a code to {email}.</div>
      <div style={{ color: themeToken.colorText }}>Please enter the code to sign in.</div>
      <br />
      <Input
        placeholder="Enter code"
        value={inputCode}
        onChange={(e) => setInputCode(e.target.value)}
        style={{ borderColor: themeToken.colorBorderSecondary }}
      />
      <br />
    </>
  );
};

const OidcAccountLink: React.FC = () => {
  const { token: themeToken } = useToken();
  const [currentStep, setCurrentStep] = useState<number>(1);
  const [inputCode, setInputCode] = useState<string>('');
  const [secret, setSecret] = useState<string | undefined>(undefined);

  // Use useLocation to access query parameters
  const location = useLocation();
  const urlParams = new URLSearchParams(location.search || location.hash.slice(location.hash.indexOf('?') + 1));
  const email = decodeURIComponent(urlParams.get('email') || '');
  const authType = capitalizeWithRegex(decodeURIComponent(urlParams.get('auth_type') || ''));

  const Step1Content = () => (
    <>
      <div style={{ fontSize: '18px', fontWeight: 500, color: themeToken.colorText }}>
        Link your {authType} credentials to your RustDesk account
      </div>
      <br />
      <div style={{ color: themeToken.colorText }}>The email ({email}) in your {authType} profile is already a RustDesk account.</div>
      <br />
      <div style={{ color: themeToken.colorText }}>We'll link your {authType} credentials to this account to let you access it by signing in to {authType}.</div>
      <br />
      <div style={{ color: themeToken.colorText }}>To set this up, we first need to verify your identity</div>
    </>
  );

  const Step3Content = () => (
    <>
      <div style={{ fontSize: '18px', fontWeight: 500, color: themeToken.colorText }}>
        You're all set
      </div>
      <br />
      <div style={{ color: themeToken.colorText }}>
        Your {authType} account has been successfully linked to your existing RustDesk account (<strong style={{ color: themeToken.colorTextBase }}>{email}</strong>).
      </div>
      <br />
      <div style={{ color: themeToken.colorText }}>
        From now on, you can sign in through {authType}.
      </div>
    </>
  );

  const handleNextClick = async () => {
    try {
      if (currentStep === 1) {
        try {
          const { secret: receivedSecret } = await getLoginVerificationCode({
            data: { email },
          });
          message.success(t("Verification code sent successfully"));
          setSecret(receivedSecret);
          setCurrentStep(2);
        } catch (e) {
          if (typeof e == 'string') {
            message.error(e as string);
            return;
          }
          const err = e as ResponseError;
          if (err.response?.status == 401) {
            message.error(t("Failed to get verification code: the user with this email doesn't exist"));
          }
          window.location.href = `${window.location.origin}/#/user/login`;
        }
      } else if (currentStep === 2) {
        if (inputCode && secret) {
          try {
            await linkOidcAccount({ email, secret, code: inputCode.trim() });
            setCurrentStep(3);
          } catch (error) {
            message.error("Failed to link OIDC account.");
          }
        } else {
          message.error("Invalid verification code.");
        }
      } else if (currentStep === 3) {
        window.location.href = `${window.location.origin}/#/user/login`;
      }
    } catch (error: any) {
      if (axios.isAxiosError(error)) {
        message.error(error.response?.data?.error);
      } else {
        message.error(error);
      }
    }
  };

  return fallbackEnUs(
    <div className={styles.container} style={{ backgroundColor: themeToken.colorBgContainer }}>
      <LangAndTheme />
      <div className={styles.content}>
        <div style={{
          display: 'flex',
          justifyContent: 'center',
          alignItems: 'center',
        }}>
          <ProCard
            title={<div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
              <img alt="logo" src="./logo.svg" />
              <span style={{ color: themeToken.colorText }}>RustDesk</span>
            </div>}
            style={{
              maxWidth: 400,
              backgroundColor: themeToken.colorBgContainer,
              color: themeToken.colorText,
              borderColor: themeToken.colorBorderSecondary
            }}
            boxShadow
            headStyle={{
              color: themeToken.colorText,
              backgroundColor: themeToken.colorBgContainer,
              borderColor: themeToken.colorBorderSecondary
            }}
          >
            <div style={{ color: themeToken.colorText }}>{email}</div>
            <br />
            {currentStep === 1 ? <Step1Content /> :
              currentStep === 2 ? <Step2Content inputCode={inputCode} setInputCode={setInputCode} email={email} /> :
                <Step3Content />}
            <br />
            <div style={{ display: 'flex', justifyContent: 'flex-end' }}>
              <Button
                type="primary"
                onClick={handleNextClick}
                disabled={currentStep === 2 && inputCode.trim().length !== 6}
              >
                <span style={{ color: 'inherit' }}>
                  {currentStep === 1 ? 'Next' :
                    currentStep === 3 ? 'Got it' :
                      'Sign in'}
                </span>
              </Button>
            </div>
          </ProCard>
        </div>
      </div>
      <div style={{ position: 'fixed', bottom: 0, width: '100%' }}>
        <Footer />
      </div>
    </div>
  );
};

export default OidcAccountLink;
